import React from "react";

const Cover = () => {
    return (
        <div className="ui violet segments">
            <div className="ui segment grid-top top-cover"></div>
            <div className="ui segment choices">
                <button className="circular ui grid-top inverted right labeled icon purple button"><i className="right arrow icon"></i>Front/Back-end Developer</button>
                <button className="circular ui grid-bottom inverted right labeled icon purple button"><i className="right arrow icon"></i>Software Engineer</button>
            </div>
            <div className="ui segment grid-bottom bottom-cover"></div>
        </div>
    )
};
export default Cover;
